const client = getClient(dataSourcesInfo);

function getConnectorErrorMessage(error) {
  if (!error) {
    return 'Unknown error';
  }

  if (typeof error === 'string') {
    return error;
  }

  if (error instanceof Error && error.message) {
    return error.message;
  }

  const candidates = [
    error.message,
    error.error && error.error.message,
    error.body && error.body.message,
    error.body && error.body.error && error.body.error.message,
    error.data && error.data.message,
    error.detail,
  ];

  const candidate = candidates.find((value) => typeof value === 'string' && value.trim() !== '');
  if (candidate) {
    return candidate;
  }

  try {
    return JSON.stringify(error);
  } catch {
    return String(error);
  }
}

async function executeConnectorOperation(operationName, parameters = {}) {
  try {
    const result = await client.executeAsync({
      connectorOperation: {
        tableName: DATA_SOURCE_NAME,
        operationName,
        parameters,
      },
    });

    if (!result) {
      throw new Error('No result returned');
    }

    if (result.success === false) {
      throw new Error(getConnectorErrorMessage(result.error));
    }

    return Object.prototype.hasOwnProperty.call(result, 'data') ? result.data : result;
  } catch (error) {
    throw new Error('Connector ' + operationName + ' failed: ' + getConnectorErrorMessage(error));
  }
}

